proof fn phi_1_execution_equality_forces_fn_equality(f: spec_fn(nat) -> int, g: spec_fn(nat) -> int)
    requires
        forall |i: nat| #[trigger] f(i) == g(i),
    ensures
        f == g,
{
    let ex1 = Execution { nat_to_state: f };
    let ex2 = Execution { nat_to_state: g };
    // If SMT can derive ex1 == ex2 from the axioms, then f == g follows from struct field equality
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_entails_preserved_by_always_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
    ensures
        always(p).entails(always(q)),
{
    entails_preserved_by_always::<int>(p, q);
}

proof fn phi_4_always_weaken_vacuous_spec(p: TempPred<int>, q: TempPred<int>)
    requires
        valid(p.implies(q)),
    ensures
        TempPred::<int>::new(|ex: Execution<int>| false).entails(always(q)),
{
    always_weaken::<int>(TempPred::new(|ex: Execution<int>| false), p, q);
}

proof fn phi_5_always_weaken_strengthens_to_valid(p: TempPred<int>, q: TempPred<int>, spec: TempPred<int>)
    requires
        valid(p.implies(q)),
        spec.entails(always(p)),
    ensures
        spec.entails(always(q)),
{
    always_weaken::<int>(spec, p, q);
}
